{

    const tlAnimatedObjectAnimationChunk* aptr = dynamic_cast<const tlAnimatedObjectAnimationChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(version == aptr->version))
    {
        return false;
    }
    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    if(!(framerate == aptr->framerate))
    {
        return false;
    }
    if(!(numcontrollers == aptr->numcontrollers))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlAnimatedObjectAnimationChunk::NameCompare(const tlDataChunk& a)
{

    const tlAnimatedObjectAnimationChunk* aptr = dynamic_cast<const tlAnimatedObjectAnimationChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }

    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    return true;
}


tlDataChunk*
tlAnimatedObjectAnimationChunk::Create(tlReadChunk16* ch)
{
    tlDataChunk* dtCh = new tlAnimatedObjectAnimationChunk(ch);
    return dtCh;
}

void
tlAnimatedObjectAnimationChunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

        f->PutLong(version);
        f->PutPString(name);
        f->PutFloat(framerate);
        f->PutLong(numcontrollers);

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlAnimatedObjectAnimationChunk::Print(int indent, unsigned int printdepth, unsigned int typemask)
{

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlAnimatedObjectAnimationChunk (%4x)\n",indent,"",(int) ident);
    printf("%*s  Version        = %ld\n",indent,"",version);
    printf("%*s  Name           = \"%s\"\n",indent,"",name);
    printf("%*s  FrameRate      = %f\n",indent,"",framerate);
    printf("%*s  NumControllers = %ld\n",indent,"",numcontrollers);

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

void
tlAnimatedObjectAnimationChunk::PrintFormatted(int indent)
{
    printf("%*schunk 0x%04x  \n",indent,"",(int) ident);
    printf("%*s  int   %12ld # Version       \n",indent,"",version);
    printf("%*s  pstring \"%s\" # Name          \n",indent,"",name);
    printf("%*s  float %12f # FrameRate     \n",indent,"",framerate);
    printf("%*s  int   %12ld # NumControllers\n",indent,"",numcontrollers);
    if(subcount)
    {
        for(int i=0;i<subcount;i++)
        {
            GetSubChunk(i)->PrintFormatted(indent+2);
        }
    }
    printf("%*sendchunk\n",indent,"");
}

