bool 
tlAnimatedObjectAnimationChunk::GetFieldValue(int fieldIndex, char* val, int len) const
{
    char buf[65536];

    switch(fieldIndex)
    {
        case 0:
            sprintf(buf, "%ld", version);
            strncpy(val, buf, len);
            return true;

        case 1:
            sprintf(buf, "%s", name);
            strncpy(val, buf, len);
            return true;

        case 2:
            sprintf(buf, "%f", framerate);
            strncpy(val, buf, len);
            return true;

        case 3:
            sprintf(buf, "%ld", numcontrollers);
            strncpy(val, buf, len);
            return true;

        default:
            return false;
    }
}

